#include <bits/stdc++.h>
using namespace std;

const int N=10;
const double Pi=3.1415926;

int n,lx,rx,ly,ry,x[N],y[N];
double r[N],ans,dis[N][N];
bool b[N];

void dfs(int p,double sum){
    if(p>n){
        ans=max(ans,sum);
        return;
    }
    for(int i=1;i<=n;i++)
        if(!b[i]){
            r[i]=min(min(x[i]-lx,rx-x[i]),min(y[i]-ly,ry-y[i]));
            for(int j=1;j<=n;j++)
                if(b[j])
                    r[i]=min(r[i],dis[i][j]-r[j]);
            r[i]=max(r[i],0.0);
            b[i]=1;
            dfs(p+1,sum+Pi*r[i]*r[i]);
            b[i]=0;
        }
}

int main(){
    scanf("%d%d%d%d%d",&n,&lx,&ly,&rx,&ry);
    if(lx>rx) swap(lx,rx);
    if(ly>ry) swap(ly,ry);
    for(int i=1;i<=n;i++)
        scanf("%d%d",&x[i],&y[i]);
    for(int i=1;i<=n;i++)
        for(int j=1;j<=n;j++)
            dis[i][j]=sqrt((x[i]-x[j])*(x[i]-x[j])+(y[i]-y[j])*(y[i]-y[j]));
    dfs(1,0.0);
    printf("%.0lf",(rx-lx)*(ry-ly)-ans);
    return 0;
}
